def get_input_folder():
    if SOURCE_MODE == "drive":
        if not os.path.isdir(INPUT_FOLDER):
            raise FileNotFoundError(f"Drive folder not found: {INPUT_FOLDER}")
        return INPUT_FOLDER

    elif SOURCE_MODE == "zip":
        uploaded = files.upload()
        zip_name = list(uploaded.keys())[0]

        if os.path.exists(ZIP_EXTRACT_FOLDER):
            shutil.rmtree(ZIP_EXTRACT_FOLDER)
        os.makedirs(ZIP_EXTRACT_FOLDER, exist_ok=True)

        with zipfile.ZipFile(zip_name, "r") as zf:
            zf.extractall(ZIP_EXTRACT_FOLDER)

        return ZIP_EXTRACT_FOLDER

    else:
        raise ValueError("SOURCE_MODE must be either 'drive' or 'zip'.")

