def find_aedtplt_files(folder):
    pattern = os.path.join(folder, "**", "*.aedtplt")
    file_list = glob.glob(pattern, recursive=True)
    file_list = sorted(file_list)
    if len(file_list) == 0:
        raise FileNotFoundError(f"No .aedtplt files found in: {folder}")
    return file_list

