    zr = np.max(coords[:, 2]) - np.min(coords[:, 2])

    ranges = {"x": xr, "y": yr, "z": zr}
    fixed_axis = min(ranges, key=ranges.get)

    if fixed_axis == "x":
        plane = "YZ"
